import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';

function Home({ showSidebar, setShowSidebar, setSidebarGender }) {

  return (
    <div style={{
      width: '100%',
      display: 'flex',
      flexDirection: 'column',
      backgroundColor: '#fff',
      margin: 0,
      padding: 0
    }}>
      {/* Video Section */}
      <div style={{
        width: '100%',
        height: '100vh',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        position: 'relative',
        overflow: 'hidden',
        backgroundColor: '#000',
        margin: 0,
        padding: 0,
        flexShrink: 0
      }}>
        {/* Video Background */}
        <video
          autoPlay
          muted
          loop
          style={{
            position: 'absolute',
            top: 0,
            left: 0,
            width: '100%',
            height: '100%',
            objectFit: 'fill',
            zIndex: 1
          }}
        >
          <source src="/HomepageVideo.mp4" type="video/mp4" />
        </video>

        {/* Dark overlay */}
        <div style={{
          position: 'absolute',
          top: 0,
          left: 0,
          width: '100%',
          height: '100%',
          backgroundColor: 'rgba(0, 0, 0, 0.3)',
          zIndex: 2
        }} />

        {/* Text overlay - no background bar */}
        <div style={{
          position: 'absolute',
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          justifyContent: 'center',
          zIndex: 3
        }}>
          {/* Season text */}
          <h1 style={{
            fontSize: '64px',
            fontFamily: 'Helvetica, Arial, sans-serif',
            fontWeight: '700',
            letterSpacing: '0.001px',
            color: '#fff',
            margin: '0 0 20px 0',
            textAlign: 'center'
          }}>
            ONLY RAW MATERIAL ALLOWED.
          </h1>

          {/* Browse collection link */}
          <Link to="/women" style={{
            fontSize: '12px',
            fontFamily: 'Helvetica, Arial, sans-serif',
            fontWeight: '300',
            letterSpacing: '0.03px',
            color: '#fff',
            backgroundColor: 'transparent',
            border: 'none',
            textDecoration: 'none',
            cursor: 'pointer',
            transition: 'all 0.3s'
          }}>
            BROWSE COLLECTION
          </Link>
        </div>

        {/* Sliding Sidebar Overlay */}
        {showSidebar && (
          <div
            style={{
              position: 'fixed',
              top: 0,
              left: 0,
              width: '100%',
              height: '100%',
              backgroundColor: 'rgba(0, 0, 0, 0.5)',
              zIndex: 100,
              animation: 'fadeIn 0.3s ease'
            }}
            onClick={() => setShowSidebar(false)}
          />
        )}

        {/* Sidebar Panel */}
        <div
          style={{
            position: 'fixed',
            top: 0,
            left: 0,
            width: '320px',
            height: '100vh',
            backgroundColor: 'rgba(255, 255, 255, 0.95)',
            zIndex: 101,
            padding: '50px 40px',
            boxSizing: 'border-box',
            overflowY: 'auto',
            transform: showSidebar ? 'translateX(0)' : 'translateX(-100%)',
            transition: 'transform 0.4s ease',
            fontFamily: 'Helvetica, Arial, sans-serif'
          }}
        >
          {/* Close Button */}
          <button
            onClick={() => setShowSidebar(false)}
            style={{
              position: 'absolute',
              top: '30px',
              right: '30px',
              background: 'none',
              border: 'none',
              fontSize: '24px',
              color: '#000',
              cursor: 'pointer',
              padding: '0'
            }}
          >
            ×
          </button>

          {/* Sidebar Title - Just Gender Name */}
          <h2 style={{
            fontSize: '16px',
            fontFamily: 'Helvetica, Arial, sans-serif',
            fontWeight: '400',
            letterSpacing: '0.5px',
            textTransform: 'uppercase',
            color: '#000',
            margin: '0 0 35px 0',
            lineHeight: '1.4'
          }}>
            {sidebarGender}
          </h2>

          {/* View All Button */}
          <Link
            to={`/${sidebarGender.toLowerCase()}`}
            onClick={() => setShowSidebar(false)}
            style={{
              fontSize: '13px',
              fontFamily: 'Helvetica, Arial, sans-serif',
              fontWeight: '300',
              letterSpacing: '0.3px',
              color: '#000',
              padding: '16px 0',
              cursor: 'pointer',
              borderBottom: '1px solid #e5e5e5',
              marginBottom: '30px',
              transition: 'color 0.3s',
              display: 'block',
              textDecoration: 'none'
            }}
            onMouseEnter={(e) => e.target.style.color = '#999'}
            onMouseLeave={(e) => e.target.style.color = '#000'}
          >
            View All
          </Link>

          {/* Subcategories or Perfume Items */}
          <div style={{ marginBottom: '40px' }}>
            {sidebarGender === 'PERFUMERY' ? (
              // Show Perfume Names
              perfumeItems.map((perfume) => (
                <Link
                  key={perfume.id}
                  to={`/product/${perfume.id}`}
                  onClick={() => setShowSidebar(false)}
                  style={{
                    fontSize: '13px',
                    fontFamily: 'Helvetica, Arial, sans-serif',
                    fontWeight: '300',
                    letterSpacing: '0.3px',
                    color: '#000',
                    padding: '16px 0',
                    cursor: 'pointer',
                    borderBottom: '1px solid #e5e5e5',
                    transition: 'color 0.3s',
                    display: 'block',
                    textDecoration: 'none'
                  }}
                  onMouseEnter={(e) => e.target.style.color = '#999'}
                  onMouseLeave={(e) => e.target.style.color = '#000'}
                >
                  {perfume.name}
                </Link>
              ))
            ) : (
              // Show Categories for Men/Women
              subCategoryItems.map((item) => (
                <Link
                  key={item}
                  to={`/${sidebarGender.toLowerCase()}?category=${item.toLowerCase()}`}
                  onClick={() => setShowSidebar(false)}
                  style={{
                    fontSize: '13px',
                    fontFamily: 'Helvetica, Arial, sans-serif',
                    fontWeight: '300',
                    letterSpacing: '0.3px',
                    color: '#000',
                    padding: '16px 0',
                    cursor: 'pointer',
                    borderBottom: '1px solid #e5e5e5',
                    transition: 'color 0.3s',
                    display: 'block',
                    textDecoration: 'none'
                  }}
                  onMouseEnter={(e) => e.target.style.color = '#999'}
                  onMouseLeave={(e) => e.target.style.color = '#000'}
                >
                  {item}
                </Link>
              ))
            )}
          </div>

          {/* Description at bottom */}
          <div style={{
            marginTop: 'auto',
            paddingTop: '40px',
            borderTop: '1px solid #e5e5e5',
            fontSize: '11px',
            fontWeight: '300',
            letterSpacing: '0.3px',
            color: '#999',
            lineHeight: '1.6'
          }}>
            Discover our latest premium {sidebarGender.toLowerCase()} collection crafted from the finest materials.
          </div>
        </div>
      </div>

      {/* Images Section */}
      <div style={{
        display: 'grid',
        gridTemplateColumns: 'repeat(2, 1fr)',
        gap: '0',
        padding: '0',
        backgroundColor: '#fff'
      }}>
        {/* Picture 1 */}
        <Link to="/" style={{
          position: 'relative',
          overflow: 'hidden',
          textDecoration: 'none',
          cursor: 'pointer',
          display: 'block'
        }}>
          <img
            src="/HomePagePics1.png"
            alt="Collection 1"
            style={{
              width: '100%',
              height: 'auto',
              objectFit: 'cover',
              transition: 'transform 0.3s ease'
            }}
          />
